We need a new file for our vec3 struct. To do this, create a new file in the same folder as main.rs, naming vec3.rs, and add mod vec3; to the top of the main.rs. Here is my implementation of Vec3 struct use core::ops::*; #[derive(Debug)]
pub struct Vec3 { e: (f64, f64, f64),
} pub type Point3 = Vec3;
pub type Color = Vec3; impl Vec3 { pub fn new() -> Vec3 { Vec3 { e: (0f64, 0f64, 0f64), } } pub fn from(e0: f64, e1: f64, e2: f64) -> Vec3 { Vec3 { e: (e0, e1, e2) } } pub fn x(&self) -> &f64 { &self.e.0 } pub fn y(&self) -> &f64 { &self.e.1 } pub fn z(&self) -> &f64 { &self.e.2 } pub fn length(&self) -> f64 { self.length_squared().sqrt() } pub fn length_squared(&self) -> f64 { self.x() * self.x() + self.y() * self.y() + self.z() * self.z() }
} It's safe and convenient to implement clone and copy for our Vec3 struct, as it can be cloned by only clone the memory, it's completely safe: impl Clone for Vec3 { fn clone(&self) -> Self { Self { e: (*self.x(), *self.y(), *self.z()), } }
} impl Copy for Vec3 {} And then, implement some operator trait for it impl Neg for Vec3 { type Output = Vec3; fn neg(self) -> Self::Output { Self { e: (-self.x(), -self.y(), -self.z()), } }
} impl AddAssign for Vec3 { fn add_assign(&mut self, rhs: Self) { self.e.0 += rhs.x(); self.e.1 += rhs.y(); self.e.2 += rhs.z(); }
} impl MulAssign<f64> for Vec3 { fn mul_assign(&mut self, rhs: f64) { self.e.0 *= rhs; self.e.1 *= rhs; self.e.2 *= rhs; }
} impl DivAssign<f64> for Vec3 { fn div_assign(&mut self, rhs: f64) { self.e.0 *= 1f64 / rhs; self.e.1 *= 1f64 / rhs; self.e.2 *= 1f64 / rhs; }
} impl Index<i32> for Vec3 { type Output = f64; fn index(&self, index: i32) -> &Self::Output { assert!(index <= 2 && index >= 0); match index { 0 => self.x(), 1 => self.y(), 2 => self.z(), _ => unreachable!(), } }
} as well as some tests: #[cfg(test)]
mod test { use super::Vec3; #[test] fn basic_ops() { let vec1 = Vec3::from(1f64, 2f64, 3f64); assert_eq!(1f64, *vec1.x()); assert_eq!(2f64, *vec1.y()); assert_eq!(3f64, *vec1.z()); assert_eq!(1f64, vec1[0]); assert_eq!(2f64, vec1[1]); assert_eq!(3f64, vec1[2]); let vec2 = -vec1; assert_eq!(-1f64, *vec2.x()); assert_eq!(-2f64, *vec2.y()); assert_eq!(-3f64, *vec2.z()); let mut vec3 = Vec3::from(5f64, 3f64, 1f64); vec3 += vec2; assert_eq!(4f64, *vec3.x()); assert_eq!(1f64, *vec3.y()); assert_eq!(-2f64, *vec3.z()); vec3 *= 2f64; assert_eq!(8f64, *vec3.x()); assert_eq!(2f64, *vec3.y()); assert_eq!(-4f64, *vec3.z()); assert_eq!(9f64, Vec3::from(1f64, 2f64, 2f64).length_squared()); assert_eq!(3f64, Vec3::from(1f64, 2f64, 2f64).length()); vec3 /= 2f64; assert_eq!(4f64, *vec3.x()); assert_eq!(1f64, *vec3.y()); assert_eq!(-2f64, *vec3.z()); }
} We use f64 here, but some ray tracer use f32, that is float. Either is fine.

