The second part of the file contains vector utility functions. impl PartialEq for Vec3 { fn eq(&self, other: &Self) -> bool { self.x() == other.x() && self.y() == other.y() && self.z() == other.z() }
} impl Display for Vec3 { fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result { f.write_str(format!("{} {} {}", self[0], self[1], self[2]).as_str()) }
} impl Add for Vec3 { type Output = Self; fn add(self, rhs: Self) -> Self::Output { Self { e: (self.x() + rhs.x(), self.y() + rhs.y(), self.z() + rhs.z()), } }
} impl Sub for Vec3 { type Output = Self; fn sub(self, rhs: Self) -> Self::Output { Self { e: (self.x() - rhs.x(), self.y() - rhs.y(), self.z() - rhs.z()), } }
} impl Mul for Vec3 { type Output = Self; fn mul(self, rhs: Self) -> Self::Output { Self { e: (self.x() * rhs.x(), self.y() * rhs.y(), self.z() * rhs.z()), } }
} impl Mul<f64> for Vec3 { type Output = Self; fn mul(self, rhs: f64) -> Self::Output { Self { e: (self.x() * rhs, self.y() * rhs, self.z() * rhs), } }
} impl Mul<Vec3> for f64 { type Output = Vec3; fn mul(self, rhs: Vec3) -> Self::Output { rhs * self }
} impl Div<f64> for Vec3 { type Output = Vec3; fn div(self, rhs: f64) -> Self::Output { (1f64 / rhs) * self }
} impl Vec3 { pub fn dot(lhs: &Vec3, rhs: &Vec3) -> f64 { lhs.x() * rhs.x() + lhs.y() * rhs.y() + lhs.z() * rhs.z() } pub fn cross(lhs: &Vec3, rhs: &Vec3) -> Vec3 { Self { e: ( lhs.y() * rhs.z() - lhs.z() * rhs.y(), lhs.z() * rhs.x() - lhs.x() * rhs.z(), lhs.x() * rhs.y() - lhs.y() * rhs.x(), ), } } pub fn unit_vector(&self) -> Self { *self / self.length() }
} And it's test: #[test] fn utility_funtions() { let vec1 = Vec3::from(1f64, 2f64, 3f64); assert_eq!(String::from("1 2 3"), vec1.to_string()); let vec2 = Vec3::from(2f64, 3f64, 4f64); let vec3 = vec1 + vec2; assert_eq!(3f64, *vec3.x()); assert_eq!(5f64, *vec3.y()); assert_eq!(7f64, *vec3.z()); let vec4 = vec3 - vec2; assert_eq!(vec4.x(), vec1.x()); assert_eq!(vec4.y(), vec1.y()); assert_eq!(vec4.z(), vec1.z()); let vec5 = vec4 * vec2; assert_eq!(2f64, *vec5.x()); assert_eq!(6f64, *vec5.y()); assert_eq!(12f64, *vec5.z()); let vec6 = vec4 * 2f64; assert_eq!(2f64, *vec6.x()); assert_eq!(4f64, *vec6.y()); assert_eq!(6f64, *vec6.z()); let vec6 = 2f64 * vec4; assert_eq!(2f64, *vec6.x()); assert_eq!(4f64, *vec6.y()); assert_eq!(6f64, *vec6.z()); let vec7 = vec6 / 2f64; assert_eq!(1f64, *vec7.x()); assert_eq!(2f64, *vec7.y()); assert_eq!(3f64, *vec7.z()); assert_eq!(14f64, Vec3::dot(&vec7, &vec1)); assert_eq!(Vec3::from(1f64, -2f64, 1f64), Vec3::cross(&vec3, &vec1)); assert_eq!( Vec3::from(1f64 / 3f64, 2f64 / 3f64, 2f64 / 3f64), Vec3::from(1f64, 2f64, 2f64).unit_vector() ) }

