Using our Vec3 struct, we'll create a utility function to write a single pixel's color out to the standard output stream. Write the following code to a new file called color.rs, add mod color; to the top of main again. use crate::vec3::*; pub fn write_color<T: std::io::Write>(mut fmt: T, pixel_color: Color) -> std::io::Result<()> { fmt.write_fmt(format_args!( "{} {} {}\n", (255.999 * pixel_color.x()) as i32, (255.999 * pixel_color.y()) as i32, (255.999 * pixel_color.z()) as i32 ))
} Now we can change our main to use this: use crate::color::*;
use crate::vec3::*; mod color;
mod vec3; fn main() { const IMAGE_WIDTH: i32 = 256; const IMAGE_HEIGHT: i32 = 256; println!("P3\n{IMAGE_WIDTH} {IMAGE_HEIGHT}\n255"); for j in (0..IMAGE_HEIGHT).rev() { eprintln!("\rScanlines remaining: {j}"); for i in 0..IMAGE_WIDTH { let pixel_color: Color = Color::from( (i as f64) / (IMAGE_WIDTH as f64 - 1f64), (j as f64) / (IMAGE_HEIGHT as f64 - 1f64), 0.25, ); write_color(std::io::stdout(), pixel_color).unwrap(); } } eprintln!("\nDone");
} This should be able to generate the same output as the previous Chapter.
